import{_ as a,p as n,q as e,a1 as s}from"./framework-5866ffd3.js";const i={},d=s(`<h1 id="umount" tabindex="-1"><a class="header-anchor" href="#umount" aria-hidden="true">#</a> umount</h1><p>用于卸载已经加载的文件系统</p><h2 id="补充说明" tabindex="-1"><a class="header-anchor" href="#补充说明" aria-hidden="true">#</a> 补充说明</h2><p><strong>umount命令</strong> 用于卸载已经加载的文件系统。利用设备名或挂载点都能umount文件系统，不过最好还是通过挂载点卸载，以免使用绑定挂载（一个设备，多个挂载点）时产生混乱。</p><h3 id="语法" tabindex="-1"><a class="header-anchor" href="#语法" aria-hidden="true">#</a> 语法</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>umount<span class="token punctuation">(</span>选项<span class="token punctuation">)</span><span class="token punctuation">(</span>参数<span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="选项" tabindex="-1"><a class="header-anchor" href="#选项" aria-hidden="true">#</a> 选项</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>-a：卸除/etc/mtab中记录的所有文件系统；
-h：显示帮助；
-n：卸除时不要将信息存入/etc/mtab文件中；
-r：若无法成功卸除，则尝试以只读的方式重新挂入文件系统；
-t<span class="token operator">&lt;</span>文件系统类型<span class="token operator">&gt;</span>：仅卸除选项中所指定的文件系统；
-v：执行时显示详细的信息；
-V：显示版本信息。
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="参数" tabindex="-1"><a class="header-anchor" href="#参数" aria-hidden="true">#</a> 参数</h3><p>文件系统：指定要卸载的文件系统或者其对应的设备文件名。</p><h3 id="实例" tabindex="-1"><a class="header-anchor" href="#实例" aria-hidden="true">#</a> 实例</h3><p>下面两条命令分别通过设备名和挂载点卸载文件系统，同时输出详细信息：</p><p>通过设备名卸载</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">umount</span> <span class="token parameter variable">-v</span> /dev/sda1
/dev/sda1 umounted
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>通过挂载点卸载</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">umount</span> <span class="token parameter variable">-v</span> /mnt/mymount/
/tmp/diskboot.img umounted
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>如果设备正忙，卸载即告失败。卸载失败的常见原因是，某个打开的shell当前目录为挂载点里的某个目录：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">umount</span> <span class="token parameter variable">-v</span> /mnt/mymount/
umount: /mnt/mymount: device is busy
umount: /mnt/mymount: device is busy
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>有时，导致设备忙的原因并不好找。碰到这种情况时，可以用lsof列出已打开文件，然后搜索列表查找待卸载的挂载点：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">lsof</span> <span class="token operator">|</span> <span class="token function">grep</span> mymount         查找mymount分区里打开的文件
<span class="token function">bash</span>   <span class="token number">9341</span>  francois  cwd   DIR   <span class="token number">8,1</span>   <span class="token number">1024</span>    <span class="token number">2</span> /mnt/mymount
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>从上面的输出可知，mymount分区无法卸载的原因在于，francois运行的PID为9341的bash进程。</p><p>对付系统文件正忙的另一种方法是执行延迟卸载：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">umount</span> <span class="token parameter variable">-vl</span> /mnt/mymount/     执行延迟卸载
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>延迟卸载（lazy unmount）会立即卸载目录树里的文件系统，等到设备不再繁忙时才清理所有相关资源。卸载可移动存储介质还可以用eject命令。下面这条命令会卸载cd并弹出CD：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">eject</span> /dev/cdrom      卸载并弹出CD 
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div>`,25),t=[d];function l(r,u){return n(),e("div",null,t)}const o=a(i,[["render",l],["__file","umount.html.vue"]]);export{o as default};
